import{c as t,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse(`{"title":"Vibe Coding and Agentic Engineering Are Getting Closer Than I'd Like","description":"","frontmatter":{"url":"https://simonwillison.net/2026/May/6/vibe-coding-and-agentic-engineering/","date":"2026-05-06T00:00:00.000Z","authors":"Simon Willison","source":"Simon Willison's Weblog","tags":["vibe-coding","code-review","agentic-engineering","productivity","review-culture"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-06-simonwillison-vibe-coding-agentic-engineering.md","filePath":"research/ai-articles/scored/2026-05-06-simonwillison-vibe-coding-agentic-engineering.md","lastUpdated":1779894392000}`),i={name:"research/ai-articles/scored/2026-05-06-simonwillison-vibe-coding-agentic-engineering.md"};function o(s,e,d,l,c,g){return a(),n("div",null,[...e[0]||(e[0]=[r(`<h1 id="vibe-coding-and-agentic-engineering-are-getting-closer-than-i-d-like" tabindex="-1">Vibe Coding and Agentic Engineering Are Getting Closer Than I&#39;d Like <a class="header-anchor" href="#vibe-coding-and-agentic-engineering-are-getting-closer-than-i-d-like" aria-label="Permalink to &quot;Vibe Coding and Agentic Engineering Are Getting Closer Than I&#39;d Like&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://simonwillison.net/2026/May/6/vibe-coding-and-agentic-engineering/" target="_blank" rel="noreferrer">https://simonwillison.net/2026/May/6/vibe-coding-and-agentic-engineering/</a><br><strong>作者</strong>：Simon Willison<br><strong>歸檔日期</strong>：2026-05-10</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>Code review 文化轉向建議可行動</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>觀察性文章，非新方法論</td></tr><tr><td>C. 證據品質</td><td>5/10</td><td>個人觀察為主，無實驗數據</td></tr><tr><td>D. 技術深度</td><td>5/10</td><td>概念層次，無實作細節</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>跨團隊適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.35/10</strong></td><td>7×0.3 + 6×0.2 + 5×0.2 + 5×0.15 + 8×0.15 = 6.35</td></tr></tbody></table><p><strong>整合決策</strong>：存入 scored（分數 &gt; 6）；不直接整合規則（觀察性，非處方性）<br><strong>整合位置</strong>：作為 code review culture shift 的參考文獻<br><strong>整合狀態</strong>：已歸檔，不整合</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>「Vibe coding」（不看 AI 輸出直接接受）和「agentic engineering」（負責任的 agent 驅動開發）之間的界線正在模糊。生產力提升（200→2,000 行/天）讓傳統 code review 不實際，迫使評估標準移至設計決策和真實世界驗證，而非工件審查。</p><hr><h2 id="核心觀察" tabindex="-1">核心觀察 <a class="header-anchor" href="#核心觀察" aria-label="Permalink to &quot;核心觀察&quot;">​</a></h2><h3 id="_1-生產力-vs-可審計性的張力" tabindex="-1">1. 生產力 vs 可審計性的張力 <a class="header-anchor" href="#_1-生產力-vs-可審計性的張力" aria-label="Permalink to &quot;1. 生產力 vs 可審計性的張力&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>生產力提升：200 行/天 → 2,000 行/天（10x）</span></span>
<span class="line"><span>Code review 速度：沒有提升（人還是那個人）</span></span>
<span class="line"><span>結果：review backlog 爆炸 → review 品質下降 → 實質上是 vibe coding</span></span></code></pre></div><h3 id="_2-評估上移-upstream-evaluation" tabindex="-1">2. 評估上移（Upstream Evaluation） <a class="header-anchor" href="#_2-評估上移-upstream-evaluation" aria-label="Permalink to &quot;2. 評估上移（Upstream Evaluation）&quot;">​</a></h3><p>解決方案不是「更快 review 程式碼」，而是「評估的上移」：</p><ul><li><strong>設計評估</strong>：在 implementation 前評估架構決策</li><li><strong>真實驗證</strong>：部署後看行為，而非靠 code review 推斷行為</li><li><strong>Harness 評估</strong>：評估 harness 約束是否足夠，而非 review 每行 code</li></ul><h3 id="_3-對-harness-的啟示" tabindex="-1">3. 對 harness 的啟示 <a class="header-anchor" href="#_3-對-harness-的啟示" aria-label="Permalink to &quot;3. 對 harness 的啟示&quot;">​</a></h3><blockquote><p>&quot;If you can&#39;t review AI-generated code line by line, you need a harness strong enough to prevent bad code from reaching production.&quot;</p></blockquote><p>Vibe coding 的興起是「我們需要更強 harness」的另一個論點。</p><hr><h2 id="對-cc-workspace-的映射" tabindex="-1">對 cc-workspace 的映射 <a class="header-anchor" href="#對-cc-workspace-的映射" aria-label="Permalink to &quot;對 cc-workspace 的映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>觀察</th><th>cc-workspace 對應</th></tr></thead><tbody><tr><td>評估上移</td><td><code>plan-mode-expert</code> 設計前評估</td></tr><tr><td>真實驗證 &gt; code review</td><td><code>healthcheck.sh</code> + 整合測試</td></tr><tr><td>Harness 約束替代 review</td><td>PreToolUse hooks + permission model</td></tr></tbody></table><p><strong>關聯</strong>：Datadog Harness-First 文章（2026-03-09）提供了此觀察的系統化解決方案。</p><hr><h2 id="與-karpathy-的連結" tabindex="-1">與 Karpathy 的連結 <a class="header-anchor" href="#與-karpathy-的連結" aria-label="Permalink to &quot;與 Karpathy 的連結&quot;">​</a></h2><p>Karpathy「context engineering」（2025-06）+ Willison「評估上移」（2026-05）→ 共同方向：<br><strong>品質保證的重心從「輸出審查」移向「輸入工程（context + harness）」</strong>。</p>`,26)])])}const b=t(i,[["render",o]]);export{p as __pageData,b as default};
